import json
from flask import Flask, request, jsonify
import pymysql

app = Flask(__name__)

@app.route('/search', methods=['GET'])
def search():
    # Get the HTTP request parameters
    query_params = request.args
    
    # Build the dynamic SQL query from the request parameters
    query = "SELECT * FROM users WHERE"
    for param in query_params:
        if param == 'name':
            query += f" name LIKE '%{query_params[param]}%'"
        elif param == 'age':
            query += f" age >= {query_params[param]}"
        else:
            continue
    
    # Connect to the Cloud SQL instance and execute the query
    conn = pymysql.connect(host='<HOST>', user='<USERNAME>', password='<PASSWORD>', db='<DATABASE>')
    cursor = conn.cursor()
    cursor.execute(query)
    
    # Return the results as JSON
    results = cursor.fetchall()
    return jsonify(results)